function EngineMiniRow({ activeSet }: { activeSet: Set<AiEngineId> }) {
  return (
    <div className="eng-mini-row">
      {AI_ENGINES.map((e) => (
        <span
          key={e.id}
          className={`eng-mini${activeSet.has(e.id) ? "" : " off"}`}
          title={e.name}
        >
          {EngineLogo[e.id]}
        </span>
      ))}
    </div>
  );
}

const num = (s: string) => {
  if (!s) return 0;
  const m = s.replace(/[,$%]/g, "").match(/-?\d+(?:\.\d+)?/);
  if (!m) return 0;
  let v = parseFloat(m[0]);
  if (/k/i.test(s)) v *= 1000;
  if (/m/i.test(s)) v *= 1_000_000;
  return v;
};

export default function AiVisibilityPage() {
  const [periodIdx, setPeriodIdx] = useState(1);
  const [selectedCat, setSelectedCat] = useState<string | null>("chair");

  type EngineSortKey = "mentions" | "traffic" | "revenue" | "revPerVisitor" | "converts";
  const [engineSort, setEngineSort] = useState<EngineSortKey>("revenue");
  const [engineDir, setEngineDir] = useState<1 | -1>(-1);

  type PageSortKey = "citations";
  const [pageSort, setPageSort] = useState<PageSortKey>("citations");
  const [pageDir, setPageDir] = useState<1 | -1>(-1);

  const sortedEngines = useMemo(() => {
    const arr = [...ENGINE_METRICS];
    arr.sort((a, b) => engineDir * (num(a[engineSort]) - num(b[engineSort])));
    return arr;
  }, [engineSort, engineDir]);

  const sortedPages = useMemo(() => {
    const arr = [...CITED_PAGES];
    arr.sort((a, b) => pageDir * (a.citations - b.citations));
    return arr;
  }, [pageDir, pageSort]);

  const onEngineSort = (k: EngineSortKey) => {
    if (engineSort === k) setEngineDir((d) => (d === 1 ? -1 : 1));
    else {
      setEngineSort(k);
      setEngineDir(-1);
    }
  };

  const selected: CategoryRow | undefined = selectedCat
    ? CATEGORIES_AI.find((c) => c.id === selectedCat)
    : CATEGORIES_AI.find((c) => c.status === "gap");

  return (
    <div className="growth-ai-visibility-page">
      <DeptHeader
        dept="growth"
        title="AI Visibility"
        meta={
          <>
            <span className="live">Live</span> · Traffic, mentions &amp; verified revenue from AI engines · matched to your orders
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button className="btn-util primary">Improve coverage →</button>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} accent="var(--d-growth)" />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">AI revenue</div>
          <div className="metric-v green"><span className="vmark" />{aiVisibilityMetrics.aiRevenue}</div>
          <div className="metric-s">{aiVisibilityMetrics.aiRevenueSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">AI traffic</div>
          <div className="metric-v">{aiVisibilityMetrics.aiTraffic}</div>
          <div className="metric-s">{aiVisibilityMetrics.aiTrafficSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Mentions</div>
          <div className="metric-v">{aiVisibilityMetrics.mentions}</div>
          <div className="metric-s">{aiVisibilityMetrics.mentionsSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Citation share</div>
          <div className="metric-v amber">{aiVisibilityMetrics.citationShare}</div>
          <div className="metric-s">{aiVisibilityMetrics.citationShareSub}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Sentiment</div>
          <div className="metric-v green">{aiVisibilityMetrics.sentiment}</div>
          <div className="metric-s">{aiVisibilityMetrics.sentimentSub}</div>
        </div>
      </div>

      {/* Conversion quality */}
      <div className="cq-panel">
        <div className="cq-head">
          <span className="cq-kicker">Conversion quality · AI visitors vs organic</span>
        </div>
        <div className="cq-grid">
          <div className="cq-cell">
            <div className="cq-label">Conversion rate</div>
            <div className="cq-val">{conversionQuality.conversionRate}</div>
            <div className="cq-cmp">
              {conversionQuality.conversionDelta}{" "}
              <span className="base">{conversionQuality.conversionBase}</span>
            </div>
          </div>
          <div className="cq-cell">
            <div className="cq-label">Order value</div>
            <div className="cq-val">{conversionQuality.orderValue}</div>
            <div className="cq-cmp">
              {conversionQuality.orderDelta}{" "}
              <span className="base">{conversionQuality.orderBase}</span>
            </div>
          </div>
          <div className="cq-cell">
            <div className="cq-label">Revenue / visitor</div>
            <div className="cq-val">{conversionQuality.revPerVisitor}</div>
            <div className="cq-cmp">
              {conversionQuality.revDelta}{" "}
              <span className="base">{conversionQuality.revBase}</span>
            </div>
          </div>
          <div className="cq-cell invisible">
            <div className="cq-label"><span className="vmark" />Invisible in GA4</div>
            <div className="cq-val">{conversionQuality.invisibleValue}</div>
            <div className="cq-sub">{conversionQuality.invisibleSub}</div>
          </div>
        </div>
      </div>

      <AIStrip label={aiVisibilityAI.label} meta={aiVisibilityAI.meta} cards={aiVisibilityAI.cards} />

      {/* ───── Engines table ───── */}
      <SectionLabel>Where AI revenue comes from — by engine</SectionLabel>
      <div className="kw-table-wrap">
        <table className="kw-table">
          <thead>
            <tr>
              <th>Engine</th>
              <Th
                k="mentions"
                label="Mentions"
                active={engineSort === "mentions"}
                dir={engineDir}
                onSort={onEngineSort}
              />
              <Th k="traffic" label="Traffic" active={engineSort === "traffic"} dir={engineDir} onSort={onEngineSort} />
              <Th
                k="revenue"
                label={<><span className="vmark" />Revenue</>}
                active={engineSort === "revenue"}
                dir={engineDir}
                onSort={onEngineSort}
              />
              <Th k="revPerVisitor" label="Rev/visitor" active={engineSort === "revPerVisitor"} dir={engineDir} onSort={onEngineSort} />
              <Th k="converts" label="Converts" active={engineSort === "converts"} dir={engineDir} onSort={onEngineSort} />
              <th className="num" data-nosort>Trend</th>
            </tr>
          </thead>
          <tbody>
            {sortedEngines.map((row) => {
              const eng = AI_ENGINES.find((e) => e.id === row.id);
              if (!eng) return null;
              return (
                <tr key={row.id} className={row.giant ? "giant" : ""}>
                  <td className="eng">
                    <div className="eng-cell">
                      <span className="eng-logo">{EngineLogo[row.id]}</span>
                      <div>
                        <div className="eng-name">{eng.name}</div>
                        <div className="eng-type">{eng.type}</div>
                      </div>
                    </div>
                  </td>
                  <td className="num">{row.mentions}</td>
                  <td className="num">{row.traffic}</td>
                  <td className="num"><span className="tk-rev">{row.revenue}</span></td>
                  <td className="num">{row.revPerVisitor}</td>
                  <td className="num">{row.converts}</td>
                  <td className="num">
                    <span className={`cp-trend ${row.trendDir}`}>{row.trend}</span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* ───── Category visibility split ───── */}
      <SectionLabel>Who AI recommends in your category</SectionLabel>
      <div className="cv-split">
        <div className="cv-main">
          {CATEGORIES_AI.map((c) => (
            <div
              key={c.id}
              className={`cv-row ${c.status}${selected?.id === c.id ? " sel" : ""}`}
              onClick={() => setSelectedCat(c.id)}
            >
              <div className="cv-q">
                <div className="cv-qname">{c.name}</div>
                <div className="cv-stand">
                  <span className={`vd ${c.status}`}>{c.standingLabel}</span>
                  <span className={`cv-trend2 ${c.trendDir}`}>{c.trendLabel}</span>
                </div>
              </div>
              <div className="cv-rank">
                <span className={`r${c.rank === "—" ? " absent" : ""}`}>{c.rank === "—" ? "—" : `#${c.rank}`}</span>
                <div className="l">{c.rank === "—" ? "0" : "of " + c.totalCited} cited</div>
              </div>
            </div>
          ))}
        </div>
        <aside className="cv-detail-aside">
          {selected && (
            <div className="cv-detail">
              <div className={`cvd-kicker ${selected.status}`}>
                <span className="kdot" />Category visibility · {selected.standingLabel}
              </div>
              <div className="cvd-name">{selected.name}</div>
              <div
                className="cvd-stand"
                dangerouslySetInnerHTML={{ __html: selected.standingSentence.replace(/#(\d)/g, "<b>#$1</b>").replace(/(\d) of \d engines/g, "<b>$&</b>") }}
              />
              <div className="cvd-block-label">Engines citing you</div>
              <div className="cvd-cited">
                <EngineMiniRow activeSet={new Set(selected.citedBy)} />
                <span className="cvd-cited-count">{selected.citedBy.length} of {AI_ENGINES.length} engines</span>
              </div>
              <div className="cvd-block-label">Who AI recommends</div>
              <div className="ladder">
                {selected.ladder.map((r) => (
                  <div key={`${r.rank}-${r.name}`} className={`rung2${r.you ? " you" : ""}`}>
                    <span className="rk">{r.rank}</span>
                    <span className="nm">
                      {r.name}
                      {r.you && <span className="tag">YOU</span>}
                    </span>
                    <EngineMiniRow activeSet={new Set(r.citedBy)} />
                  </div>
                ))}
              </div>
              <div className="cvd-line">{selected.argument}</div>
            </div>
          )}
        </aside>
      </div>

      {/* ───── Cited pages ───── */}
      <SectionLabel>Pages AI cites as a source</SectionLabel>
      <div className="kw-table-wrap">
        <table className="kw-table">
          <thead>
            <tr>
              <th>Page</th>
              <th
                className={`num${pageSort === "citations" ? " active" : ""}`}
                onClick={() => {
                  if (pageSort === "citations") setPageDir((d) => (d === 1 ? -1 : 1));
                  else {
                    setPageSort("citations");
                    setPageDir(-1);
                  }
                }}
              >
                Citations<span className="sort-ar">{pageDir < 0 ? "↓" : "↑"}</span>
              </th>
              <th data-nosort>Engines</th>
              <th className="num" data-nosort>Trend</th>
            </tr>
          </thead>
          <tbody>
            {sortedPages.map((p) => (
              <tr key={p.path}>
                <td>
                  <span className="cp-path">
                    <span className="host">{p.host}</span>
                    {p.path}
                  </span>
                </td>
                <td className="num">
                  <span className={`cp-cite${p.citations === 0 ? " zero" : ""}`}>{p.citations}</span>
                </td>
                <td>
                  <EngineMiniRow activeSet={new Set(p.citedBy)} />
                </td>
                <td className="num">
                  {p.notCited ? (
                    <span className="cp-tag none">Not cited</span>
                  ) : (
                    <span className={`cp-trend ${p.trendDir}`}>{p.trend}</span>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

interface ThProps {
  k: "mentions" | "traffic" | "revenue" | "revPerVisitor" | "converts";
  label: React.ReactNode;
  active: boolean;
  dir: 1 | -1;
  onSort: (k: ThProps["k"]) => void;
}
function Th({ k, label, active, dir, onSort }: ThProps) {
  return (
    <th className={`num${active ? " active" : ""}`} onClick={() => onSort(k)}>
      {label}
      <span className="sort-ar">{active && dir < 0 ? "↓" : "↑"}</span>
    </th>
  );
}
