export type AiTrend = "up" | "down" | "flat";

export interface EngineMetricsRow {
  id: AiEngineId;
  mentions: string;
  traffic: string;
  revenue: string;
  revPerVisitor: string;
  converts: string;
  trend: string;
  trendDir: AiTrend;
  /** First row gets the giant treatment (highlighted background). */
  giant?: boolean;
}

