export type CategoryStatus = "lead" | "present" | "gap" | "absent";

export interface LadderRung {
  rank: number | "—";
  /** Brand or "You". */
  name: string;
  /** Optional "YOU" tag flag. */
  you?: boolean;
  /** Engines where this brand is cited for this query. */
  citedBy: AiEngineId[];
}

export interface CategoryRow {
  id: string;
  /** Query phrase, e.g. "best ergonomic chair 2026". */
  name: string;
  status: CategoryStatus;
  /** "You lead" · "Cited" · "Competitors ahead" · "Not recommended". */
  standingLabel: string;
  /** "Holding #1" · "+1 engine vs last month" · "deskhaus pulled ahead" etc. */
  trendLabel: string;
  trendDir: AiTrend;
  rank: number | "—";
  totalCited: number;
  /** Engines that cite you for this query. */
  citedBy: AiEngineId[];
  /** Standing sentence shown in the detail panel. */
  standingSentence: string;
  /** Argument line at the bottom of the detail panel. */
  argument: string;
  /** Top 3 ranking — competitors + you (depending on the category). */
  ladder: LadderRung[];
}

